import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.util.UriComponentsBuilder;

@SpringBootApplication
public class EnterpriseOauthClientApplication {

    public static void main(String[] args) {
        SpringApplication.run(EnterpriseOauthClientApplication.class, args);
    }
}

@Controller
class AuthorizationController {

    @Value("${oauth2.client.registration.enterprise.client-id}")
    private String clientId;

    @Value("${oauth2.client.registration.enterprise.redirect-uri}")
    private String redirectUri;

    @Value("${oauth2.client.provider.enterprise.authorization-uri}")
    private String authorizationUri;

    @Value("${oauth2.client.registration.enterprise.scope}")
    private String scope;

    // This endpoint initiates the OAuth 2.0 authorization code flow
    @GetMapping("/oauth2/authorize")
    public String authorize() {
        String authorizationUrl = UriComponentsBuilder.fromUriString(authorizationUri)
                .queryParam("client_id", clientId)
                .queryParam("redirect_uri", redirectUri)
                .queryParam("scope", scope)
                .queryParam("response_type", "code") // We are using Authorization Code flow
                // .queryParam("state", "random_state_string") // Skipping state for now as per requirement
                .build()
                .toUriString();

        return "redirect:" + authorizationUrl;
    }

    // This endpoint will be the redirect_uri that the Authorization Server calls back to
    // In a real application, you would handle the authorization code here
    @GetMapping("/login/oauth2/code/enterprise")
    public String oauth2Callback(String code) {
        // For demonstration, just show the received code
        // In a real application, you would exchange this code for an access token
        return "Received authorization code: " + code + ". Please check server logs for more details if any.";
    }
}

